// The sheet's long-form status strings collapse to three kinds for filtering;
// the raw string is kept for display ("current (pilot, ~100 of ~600 Costco
// hearing centers)" says more than a chip can).
function statusKind(status) {
  if (!status.startsWith("current")) return "discontinued";
  if (/legacy|superseded|wound down/.test(status)) return "legacy";
  return "current";
}

function mapRow([channel, brand, mfgGroup, platform, family, model, bodyStyle,
  techLevels, releaseYear, status, rechargeable, bluetooth, keyFeatures, notes,
  imageUrl, sourceUrl]) {
  return {
    channel, brand, mfgGroup, platform, family, model, bodyStyle, techLevels,
    releaseYear, status, statusKind: statusKind(status),
    rechargeable, bluetooth, keyFeatures, notes, imageUrl, sourceUrl,
    verifyFlag: /verify/i.test(notes),
  };
}

export const HA_CATALOG = ROWS.map(mapRow);

